// Game Tavern (술집)
// Generated by docs/_split_game.py — Phase 4
// DO NOT hand-edit keys — edit in original and re-run splitter if needed.

RoF.__gameKeys = RoF.__gameKeys || new Set();
(function(keys){
  for (const k of keys) {
    if (RoF.__gameKeys.has(k)) {
      console.error('[Game] 중복 키 감지:', k);
      RoF.__gameKeyError = true;
    }
    RoF.__gameKeys.add(k);
  }
})(["_tavTab", "showTavern", "showTavernUnit", "showTavernHero", "genHeroRecruitCards", "_generateTavernSlots", "_ensureTavernSlots", "genTavernCards", "refreshTavern"]);

Object.assign(RoF.Game, {
  _tavTab:'unit',
  showTavern(){
    UI.show('tavern-screen');
    document.getElementById('tav-name').textContent=`👤 ${Auth.user}`;
    document.getElementById('tav-gold').textContent=this.gold;
    document.getElementById('tav-deck').textContent=this.deck.length;
    // NPC
    const npc=this.getNpc('tavern');
    const msg=this.gold<5?npc.noGold:npc.greet;
    const existing=document.getElementById('tav-npc');if(existing)existing.remove();
    document.getElementById('tav-info').insertAdjacentHTML('afterend',`<div id="tav-npc">${this.renderNpcBar('tavern',msg)}</div>`);
    this._tavTab='unit';this.showTavernUnit();
  },
  showTavernUnit(){
    this._tavTab='unit';
    document.getElementById('tav-tab-unit').style.cssText='border-color:#ffd700;color:#ffd700;';
    document.getElementById('tav-tab-hero').style.cssText='';
    document.getElementById('tav-info').textContent='골드를 지불하고 동료를 영입하세요';
    this.genTavernCards();
  },
  showTavernHero(){
    this._tavTab='hero';
    document.getElementById('tav-tab-hero').style.cssText='border-color:#ffd700;color:#ffd700;';
    document.getElementById('tav-tab-unit').style.cssText='';
    document.getElementById('tav-info').innerHTML=`✨ 신의 축복: <span style="color:#ffd700;">${this.blessings||0}개</span> | 신의 축복 1개로 영웅 동료를 소환합니다`;
    this.genHeroRecruitCards();
  },
  genHeroRecruitCards(){
    const g=document.getElementById('tav-grid');g.innerHTML='';
    if((this.blessings||0)<1){
      g.innerHTML='<div style="color:#888;text-align:center;padding:40px;">✨ 신의 축복이 부족합니다.<br><span style="font-size:.75rem;color:#555;">리그에서 승전하면 신의 축복을 얻을 수 있습니다.</span></div>';
      return;
    }
    // Generate 3 hero candidates (silver~divine)
    for(let i=0;i<3;i++){
      const roll=Math.random()*100;
      let r;
      if(roll<5)r='divine';else if(roll<20)r='legendary';else if(roll<50)r='gold';else r='silver';
      // Pick random hero unit
      let pool=UNITS.filter(u=>u.id.startsWith('h_')&&u.rarity===r);
      if(!pool.length)pool=UNITS.filter(u=>u.id.startsWith('h_'));
      const b=pool[Math.floor(Math.random()*pool.length)];
      const HERO_NAMES=['아리안','칼리스','제논','리아나','볼카르','에리나','다리우스','셀레나','오딘','이솔데','펜릭','모르가나','티리온','루나','갈라드','아스트라'];
      const heroName=HERO_NAMES[Math.floor(Math.random()*HERO_NAMES.length)];
      const c={...b,uid:uid(),name:heroName,heroClass:b.name,level:1,equips:[],maxHp:b.hp,xp:0,honor:0,freePoints:0,growthPts:{atk:0,hp:0,def:0,spd:0,nrg:0,luck:0,eva:0}};
      const el=mkCardEl(c);
      const btn=document.createElement('div');btn.style.cssText='text-align:center;margin-top:4px;';
      btn.innerHTML=`<button class="btn btn-s btn-purple" ${(this.blessings||0)<1||this.deck.length>=this.maxDeck?'disabled':''}>✨ 신의 축복 1개</button>`;
      btn.querySelector('button').onclick=(e)=>{e.stopPropagation();
        if((this.blessings||0)<1||this.deck.length>=this.maxDeck)return;
        this.blessings--;this.deck.push(c);
        SFX.play('rarity_up');
        if(b.rarity==='legendary'||b.rarity==='divine'){const rv=document.createElement('div');rv.className='tavern-reveal legendary-reveal';document.body.appendChild(rv);setTimeout(()=>rv.remove(),1000);}
        document.getElementById('tav-info').innerHTML=`✨ <span style="color:#ffd700;">${heroName}</span> 영웅이 합류했습니다!`;
        this.persist();this.showTavernHero();
      };
      const wrap=document.createElement('div');wrap.className='tavern-card-wrap';wrap.appendChild(el);wrap.appendChild(btn);g.appendChild(wrap);
      el.classList.add('tavern-card-inner');el.classList.add('flipping');setTimeout(()=>el.classList.remove('flipping'),600);
    }
  },

  // Generate tavern slots (saved to persist)
  _generateTavernSlots(){
    const tavLv=this.getBuildingLv('tavern')||1;
    const count=tavLv>=2?5:4;
    const slots=[];
    for(let i=0;i<count;i++){
      const r=pickRar(this.getHeroLevel()+tavLv*2,'tavern');
      let pool=UNITS.filter(u=>u.rarity===r&&!u.id.startsWith('h_'));
      if(!pool.length)pool=UNITS.filter(u=>!u.id.startsWith('h_'));
      const b=pool[Math.floor(Math.random()*pool.length)];
      const cost=({bronze:5,silver:8,gold:12,legendary:18,divine:25})[b.rarity]||5;
      slots.push({...b,uid:uid(),level:1,equips:[],maxHp:b.hp,cost});
    }
    return slots;
  },
  _ensureTavernSlots(){
    // Daily auto-refresh check
    const today=new Date().toDateString();
    if(this.tavernDate!==today||!this.tavernSlots){
      this.tavernSlots=this._generateTavernSlots();
      this.tavernDate=today;
      this.persist();
    }
  },
  genTavernCards(){
    this._ensureTavernSlots();
    const g=document.getElementById('tav-grid');g.innerHTML='';
    this.tavernSlots.forEach((c,idx)=>{
      if(!c){
        // Empty slot (hired already)
        const empty=document.createElement('div');empty.style.cssText='width:200px;min-height:290px;border:2px dashed #333;border-radius:8px;display:flex;align-items:center;justify-content:center;color:#444;font-size:.85rem;';
        empty.textContent='빈 자리';
        g.appendChild(empty);
        return;
      }
      const cost=c.cost||5;
      const el=mkCardEl(c);
      const btn=document.createElement('div');btn.style.cssText='text-align:center;margin-top:4px;';
      btn.innerHTML=`<button class="btn btn-s btn-green" ${this.gold<cost||this.deck.length>=this.maxDeck?'disabled':''}>${cost}💰 영입</button>`;
      btn.querySelector('button').onclick=(e)=>{e.stopPropagation();
        if(this.gold<cost||this.deck.length>=this.maxDeck)return;
        this.gold-=cost;
        const hired={...c};delete hired.cost;
        this.deck.push(hired);
        SFX.play('card_reveal');this.checkTutorial('first_recruit');
        if(c.rarity==='legendary'||c.rarity==='divine'){const rv=document.createElement('div');rv.className='tavern-reveal legendary-reveal';document.body.appendChild(rv);setTimeout(()=>rv.remove(),1000);SFX.play('rarity_up');}
        else if(c.rarity==='gold'){const rv=document.createElement('div');rv.className='tavern-reveal gold-reveal';document.body.appendChild(rv);setTimeout(()=>rv.remove(),800);}
        document.getElementById('tav-info').textContent=`✅ ${c.name} 영입 완료!`;
        // Remove from slot
        this.tavernSlots[idx]=null;
        this.persist();this.showTavernUnit();
      };
      const wrap=document.createElement('div');wrap.className='tavern-card-wrap';wrap.appendChild(el);wrap.appendChild(btn);g.appendChild(wrap);
      el.classList.add('tavern-card-inner');el.classList.add('flipping');setTimeout(()=>el.classList.remove('flipping'),600);
    });
  },

  refreshTavern(){
    if(this.gold<2){document.getElementById('tav-info').textContent='⚠️ 골드가 부족합니다!';return;}
    this.gold-=2;
    this.tavernSlots=this._generateTavernSlots();
    SFX.play('click');this.persist();this.showTavernUnit();
  },

  // ---- BATTLE ----
  // One battle = roguelike. Pick cards (by command slots) → fight rounds → all temp stuff resets after.
});
